#include "reed_switch.h"
#include <Arduino.h>
#define REED_PIN 13
static volatile uint32_t _cnt=0;static bool _closed=false;static unsigned long _l=0;
void IRAM_ATTR _reed_isr(){_cnt++;}
void reed_setup(){pinMode(REED_PIN,INPUT_PULLUP);attachInterrupt(REED_PIN,_reed_isr,FALLING);Serial.println("[reed] OK");}
void reed_loop(){if(millis()-_l<50)return;_l=millis();_closed=!digitalRead(REED_PIN);}
bool reed_is_closed(){return _closed;}
uint32_t reed_get_count(){return _cnt;}
void reed_reset_count(){_cnt=0;}
